import torch
import time

def bench(fn, n_runs=100):
    # Warm up
    for _ in range(5):
        fn()
    torch.cuda.synchronize() if torch.cuda.is_available() else None
    start = time.perf_counter()
    for _ in range(n_runs):
        fn()
    return (time.perf_counter() - start) / n_runs * 1000  # ms

# Compare Jacobian computation strategies for a small model
model = torch.nn.Linear(50, 20)
x = torch.randn(1, 50, requires_grad=True)

# Method 1: Loop over outputs
def jacobian_loop():
    y = model(x)
    J = torch.zeros(20, 50)
    for i in range(20):
        if x.grad is not None:
            x.grad.zero_()
        y[0, i].backward(retain_graph=True)
        J[i] = x.grad
    return J

# Method 2: torch.autograd.functional.jacobian
from torch.autograd.functional import jacobian as torch_jac

def jacobian_functional():
    return torch_jac(lambda inp: model(inp), x)

t_loop = bench(jacobian_loop)
t_func = bench(jacobian_functional)
print(f"Loop method:       {t_loop:.3f} ms")
print(f"Functional method: {t_func:.3f} ms")
