import torch

def hessian_vector_product_safe(loss, params, v):
    """
    Compute H·v with NaN detection.
    """
    grads = torch.autograd.grad(
        loss, params,
        create_graph=True,
        retain_graph=True,
        allow_unused=True
    )

    # Check first-order gradients
    for i, g in enumerate(grads):
        if g is None:
            raise RuntimeError(f"No gradient for param {i} — check requires_grad")
        if not torch.all(torch.isfinite(g)):
            raise RuntimeError(f"NaN/Inf in gradient of param {i}")

    grad_dot_v = sum(
        (g * vi).sum()
        for g, vi in zip(grads, v)
        if g is not None
    )

    Hv = torch.autograd.grad(grad_dot_v, params, retain_graph=True)

    # Check second-order results
    for i, hvi in enumerate(Hv):
        if not torch.all(torch.isfinite(hvi)):
            raise RuntimeError(f"NaN/Inf in HVP for param {i} — "
                               "check activation functions (avoid ReLU for 2nd-order methods)")

    return Hv
